const COMPOSER_MAP = {
  'b1':'datahub-composer-c-1-pr','b2':'datahub-composer-c-2-pr',
  'b3':'datahub-composer-c-3-pr','c1':'datahub-composer-c-1-pr',
  'c2':'datahub-composer-c-2-pr','c3':'datahub-composer-c-3-pr',
  'c4':'datahub-composer-c-4-pr','datahub-composer-2':'datahub-composer-c-2-pr'
};

const extracted = $('Extract Alert Context').first().json;
const dagId = (extracted.dag_id ?? '').trim().toLowerCase();
const composerFromPayload = (extracted.composer ?? '').trim();

// All rows from Data Table — find matching DAG (case-insensitive)
const rows = $input.all();
const match = rows.find(r => (r.json['DAG'] ?? '').trim().toLowerCase() === dagId);
const matchRow = match ? match.json : null;

let resolvedComposer = composerFromPayload;
let dag_supported = false;
let support_status = 'Not Found';
let support_reason = "DAG '" + extracted.dag_id + "' not found in SRE support table";

// Enrichment fields from the matched DataTable row
let pd_priority = '';   // 'P1' | 'P2' | '' (blank → -- in PagerDuty)
let sme = '';
let runbook = '';

if (matchRow) {
  const sheetComposer = (matchRow['Datahub Composer'] ?? '').trim();
  if (sheetComposer) {
    resolvedComposer = COMPOSER_MAP[sheetComposer] ?? sheetComposer;
  }
  const notes = (matchRow['OtherNotes'] ?? '').split(';')[0].trim();
  support_status = notes;
  if (notes.toLowerCase() === 'not supported') {
    dag_supported = false;
    support_reason = "DAG '" + extracted.dag_id + "' is explicitly marked as Not Supported";
  } else {
    dag_supported = true;
    support_reason = "DAG '" + extracted.dag_id + "' is " + notes;
  }

  // Priority: accept only P1/P2 (case-insensitive), else leave blank for --
  const rawPriority = (matchRow['Priority'] ?? '').trim().toUpperCase();
  pd_priority = (rawPriority === 'P1' || rawPriority === 'P2') ? rawPriority : '';
  sme = (matchRow['SME'] ?? '').trim();
  runbook = (matchRow['Runbook'] ?? '').trim();
  // Ensure runbook is a full URL so PagerDuty auto-linkifies it.
  if (runbook && !/^https?:\/\//i.test(runbook)) {
    runbook = 'https://' + runbook.replace(/^\/+/, '');
  }
}

return [{ json: { ...extracted, composer: resolvedComposer, dag_supported, support_status, support_reason, pd_priority, sme, runbook } }];

// Resolve the P1/P2 label from DAG Support Lookup to a PagerDuty priority ID.
// Blank or no match => priority_id null => incident priority shows as -- in PagerDuty.
const ctx = $('DAG Support Lookup').first().json;
const wanted = (ctx.pd_priority ?? '').trim().toUpperCase();

const priorities = $json.priorities ?? [];
let priority_id = null;
if (wanted) {
  const hit = priorities.find(p => (p.name ?? '').trim().toUpperCase() === wanted);
  priority_id = hit ? hit.id : null;
}

// Pre-build the request body here so the HTTP node never parses an object literal
// inside a {{ }} expression (n8n Tournament fails on `? {...} : null`).

// Pre-build the incident-note body (notes render clickable links in PagerDuty,
// unlike the text custom field). Posted only when a runbook URL exists.
const rb = (ctx.runbook ?? '').trim();
const note_text = rb ? ('Runbook: ' + rb) : '';
const has_runbook = rb ? 'true' : 'false';
const note_body = JSON.stringify({ note: { content: note_text } });

const priority_body = JSON.stringify({
  incident: {
    type: 'incident_reference',
    priority: priority_id ? { id: priority_id, type: 'priority_reference' } : null,
  },
});

return [{ json: { ...ctx, priority_id, priority_body, note_text, has_runbook, note_body } }];

